 41→/**
 42→ * Returns a flow that contains first [count] elements.
 43→ * When [count] elements are consumed, the original flow is cancelled.
 44→ * Throws [IllegalArgumentException] if [count] is not positive.
 45→ */
 46→public fun <T> Flow<T>.take(count: Int): Flow<T> {
 47→    require(count > 0) { "Requested element count $count should be positive" }
 48→    return flow {
 49→        var consumed = 0
 50→        try {
 51→            collect { value ->
 52→                // Note: this for take is not written via collectWhile on purpose.
 53→                // It checks condition first and then makes a tail-call to either emit or emitAbort.
 54→                // This way normal execution does not require a state machine, only a termination (emitAbort).
 55→                // See "TakeBenchmark" for comparision of different approaches.
 56→                if (++consumed < count) {
 57→                    return@collect emit(value)
 58→                } else {
 59→                    return@collect emitAbort(value)
 60→                }
 61→            }
 62→        } catch (e: AbortFlowException) {
 63→            e.checkOwnership(owner = this)
 64→        }
 65→    }
 66→}
 67→
 68→private suspend fun <T> FlowCollector<T>.emitAbort(value: T) {
 69→    emit(value)
 70→    throw AbortFlowException(this)
 71→}
