 73→/**
 74→ * Returns a flow that contains first elements satisfying the given [predicate].
 75→ *
 76→ * Note, that the resulting flow does not contain the element on which the [predicate] returned `false`.
 77→ * See [transformWhile] for a more flexible operator.
 78→ */
 79→public fun <T> Flow<T>.takeWhile(predicate: suspend (T) -> Boolean): Flow<T> = flow {
 80→    // This return is needed to work around a bug in JS BE: KT-39227
 81→    return@flow collectWhile { value ->
 82→        if (predicate(value)) {
 83→            emit(value)
 84→            true
 85→        } else {
 86→            false
 87→        }
 88→    }
 89→}
 90→
 91→/**
 92→ * Applies [transform] function to each value of the given flow while this
 93→ * function returns `true`.
 94→ *
 95→ * The receiver of the `transformWhile` is [FlowCollector] and thus `transformWhile` is a
 96→ * flexible function that may transform emitted element, skip it or emit it multiple times.
 97→ *
 98→ * This operator generalizes [takeWhile] and can be used as a building block for other operators.
 99→ * For example, a flow of download progress messages can be completed when the
100→ * download is done but emit this last message (unlike `takeWhile`):
101→ *
102→ * ```
103→ * fun Flow<DownloadProgress>.completeWhenDone(): Flow<DownloadProgress> =
104→ *     transformWhile { progress ->
105→ *         emit(progress) // always emit progress
106→ *         !progress.isDone() // continue while download is not done
107→ *     }
108→ * ```
109→ */
110→public fun <T, R> Flow<T>.transformWhile(
111→    @BuilderInference transform: suspend FlowCollector<R>.(value: T) -> Boolean
112→): Flow<R> =
113→    safeFlow { // Note: safe flow is used here, because collector is exposed to transform on each operation
114→        // This return is needed to work around a bug in JS BE: KT-39227
115→        return@safeFlow collectWhile { value ->
116→            transform(value)
117→        }
118→    }
119→
120→// Internal building block for non-tailcalling flow-truncating operators
121→internal suspend inline fun <T> Flow<T>.collectWhile(crossinline predicate: suspend (value: T) -> Boolean) {
122→    val collector = object : FlowCollector<T> {
123→        override suspend fun emit(value: T) {
124→            // Note: we are checking predicate first, then throw. If the predicate does suspend (calls emit, for example)
125→            // the the resulting code is never tail-suspending and produces a state-machine
126→            if (!predicate(value)) {
127→                throw AbortFlowException(this)
128→            }
129→        }
130→    }
131→    try {
132→        collect(collector)
133→    } catch (e: AbortFlowException) {
134→        e.checkOwnership(collector)
135→    }
136→}
